softmax.metal_source:
// softmax per row: exp(x - max) / sum(exp(x - max)). Numerically stable.
#include <metal_stdlib>
using namespace metal;

kernel void softmax_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * N;
    float val = x[off + t];

    // Step 1: find row max
    float row_max = simd_max(val);
    threadgroup float tg_max[32];
    uint sg = t >> 5;
    if ((t & 31) == 0) tg_max[sg] = row_max;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (t < 32) {
        row_max = tg_max[t];
        for (uint s = 16; s > 0; s >>= 1)
            row_max = max(row_max, simd_shuffle_down(row_max, s));
    }
    if (t == 0) tg_max[0] = row_max;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float rmax = tg_max[0];

    // Step 2: compute exp and sum
    float exp_val = exp(val - rmax);
    float row_sum = simd_sum(exp_val);
    threadgroup float tg_sum[32];
    if ((t & 31) == 0) tg_sum[sg] = row_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (t < 32) {
        row_sum = tg_sum[t];
        for (uint s = 16; s > 0; s >>= 1)
            row_sum += simd_shuffle_down(row_sum, s);
    }
    if (t == 0) tg_sum[0] = row_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Step 3: normalize
    y[off + t] = exp_val / tg_sum[0];
}

